const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');

const openCart = carts.find(c => c.status === 'open');
let qualifyingCartItems = [];
let cheapestCartItems = [];

if (openCart && Array.isArray(products) && products.length > 0) {
  const cartItems = cartItemsAll.filter(ci => ci.cart_id === openCart.id && ci.item_type === 'standard_product');

  const qualifyingProducts = products.filter(p => 
    p.product_type === 'tarp' &&
    p.width_ft === 20 &&
    p.length_ft === 30 &&
    p.feature_heavy_duty === true &&
    p.feature_waterproof === true &&
    typeof p.price === 'number' && p.price <= 150 &&
    typeof p.average_rating === 'number' && p.average_rating >= 4
  );

  const qualifyingProductIds = qualifyingProducts.map(p => p.id);
  qualifyingCartItems = cartItems.filter(ci => qualifyingProductIds.includes(ci.product_id) && ci.quantity > 0);

  if (qualifyingProducts.length > 0) {
    const minPrice = Math.min.apply(null, qualifyingProducts.map(p => p.price));
    const cheapestProductIds = qualifyingProducts.filter(p => p.price === minPrice).map(p => p.id);
    cheapestCartItems = cartItems.filter(ci => cheapestProductIds.includes(ci.product_id) && ci.quantity > 0);
  }
}

// CP1 (0.30): User added at least one qualifying 20x30 heavy-duty waterproof tarp under $150 with rating >= 4.0
checkpoints.push({ passed: qualifyingCartItems.length > 0, weight: 0.30 });

// CP2 (0.30): User added the cheapest qualifying tarp (by unit price) to the cart
checkpoints.push({ passed: cheapestCartItems.length > 0, weight: 0.30 });

// CP3 (0.40): User has quantity >= 2 of the cheapest qualifying tarp in the cart
const hasCheapestQty2 = cheapestCartItems.some(ci => typeof ci.quantity === 'number' && ci.quantity >= 2);
checkpoints.push({ passed: hasCheapestQty2, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

