const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');

function materialIncludes(p, keyword) {
  const m = (p.material || '').toLowerCase();
  return m.includes(keyword);
}

function isClearPoly(p) {
  const m = (p.material || '').toLowerCase();
  return m.includes('clear') && m.includes('poly');
}

const openCart = carts.find(c => c.status === 'open');
let req1Ok = false;
let req2Ok = false;
let req3Ok = false;

if (openCart && Array.isArray(products) && products.length > 0) {
  const cartItems = cartItemsAll.filter(ci => ci.cart_id === openCart.id && ci.item_type === 'standard_product');

  const itemsWithProducts = cartItems.map(ci => ({
    ci,
    product: products.find(p => p.id === ci.product_id) || null
  })).filter(x => x.product);

  // Requirement 1: 12x20 clear poly tarp under $80, quantity >= 5
  req1Ok = itemsWithProducts.some(x => 
    x.product.product_type === 'tarp' &&
    x.product.size_label === '12 ft x 20 ft' &&
    isClearPoly(x.product) &&
    typeof x.product.price === 'number' && x.product.price < 80 &&
    typeof x.ci.quantity === 'number' && x.ci.quantity >= 5
  );

  // Requirement 2: 10x10 mesh tarp priced between $40 and $70, quantity >= 3
  req2Ok = itemsWithProducts.some(x => 
    x.product.product_type === 'tarp' &&
    x.product.size_label === '10 ft x 10 ft' &&
    materialIncludes(x.product, 'mesh') &&
    typeof x.product.price === 'number' && x.product.price >= 40 && x.product.price <= 70 &&
    typeof x.ci.quantity === 'number' && x.ci.quantity >= 3
  );

  // Requirement 3: 8x12 canvas tarp under $90, quantity >= 2
  req3Ok = itemsWithProducts.some(x => 
    x.product.product_type === 'tarp' &&
    x.product.size_label === '8 ft x 12 ft' &&
    materialIncludes(x.product, 'canvas') &&
    typeof x.product.price === 'number' && x.product.price < 90 &&
    typeof x.ci.quantity === 'number' && x.ci.quantity >= 2
  );
}

// CP1 (0.34): 12x20 clear poly tarp under $80 with quantity >= 5 is in cart
checkpoints.push({ passed: req1Ok, weight: 0.34 });

// CP2 (0.33): 10x10 mesh tarp $40–$70 with quantity >= 3 is in cart
checkpoints.push({ passed: req2Ok, weight: 0.33 });

// CP3 (0.33): 8x12 canvas tarp under $90 with quantity >= 2 is in cart
checkpoints.push({ passed: req3Ok, weight: 0.33 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorites') || '[]');

const qualifyingProducts = products.filter(p => 
  p.product_type === 'tarp' &&
  p.feature_uv_resistant === true &&
  p.size_label === '16 ft x 20 ft' &&
  typeof p.price === 'number' && p.price <= 100 &&
  typeof p.average_rating === 'number' && p.average_rating >= 4.5
);

const qualifyingProductIds = qualifyingProducts.map(p => p.id);
const qualifyingFavorites = favorites.filter(f => qualifyingProductIds.includes(f.product_id));
const favoriteProductIdsSet = new Set(qualifyingFavorites.map(f => f.product_id));

let hasHighestRated = false;
let hasCheapest = false;

if (qualifyingProducts.length > 0) {
  const maxRating = Math.max.apply(null, qualifyingProducts.map(p => p.average_rating || 0));
  const highestRatedIds = qualifyingProducts.filter(p => p.average_rating === maxRating).map(p => p.id);
  hasHighestRated = highestRatedIds.some(id => favoriteProductIdsSet.has(id));

  const minPrice = Math.min.apply(null, qualifyingProducts.map(p => p.price || 0));
  const cheapestIds = qualifyingProducts.filter(p => p.price === minPrice).map(p => p.id);
  hasCheapest = cheapestIds.some(id => favoriteProductIdsSet.has(id));
}

// CP1 (0.30): User favorited at least one qualifying UV-resistant 16x20 tarp under $100 with rating >= 4.5
checkpoints.push({ passed: qualifyingFavorites.length > 0, weight: 0.30 });

// CP2 (0.35): User favorited the highest-rated qualifying tarp
checkpoints.push({ passed: hasHighestRated, weight: 0.35 });

// CP3 (0.35): User favorited the cheapest qualifying tarp
checkpoints.push({ passed: hasCheapest, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');

const openCart = carts.find(c => c.status === 'open');
let anyPalletCartItems = [];
let bestValueCartItems = [];

if (openCart && Array.isArray(products) && products.length > 0) {
  const cartItems = cartItemsAll.filter(ci => ci.cart_id === openCart.id && ci.item_type === 'standard_product');

  const palletProducts = products.filter(p => 
    p.product_type === 'pallet_cover' &&
    p.pallet_length_in === 48 &&
    p.pallet_width_in === 40 &&
    (p.pack_quantity === 25 || p.pack_quantity === 50)
  );

  const palletProductIds = palletProducts.map(p => p.id);
  anyPalletCartItems = cartItems.filter(ci => palletProductIds.includes(ci.product_id) && ci.quantity > 0);

  const priced = palletProducts.filter(p => typeof p.price === 'number' && typeof p.pack_quantity === 'number' && p.pack_quantity > 0)
    .map(p => ({ id: p.id, price_per_cover: p.price / p.pack_quantity }));

  if (priced.length > 0) {
    const minPricePerCover = Math.min.apply(null, priced.map(p => p.price_per_cover));
    const bestIds = priced.filter(p => p.price_per_cover === minPricePerCover).map(p => p.id);
    bestValueCartItems = cartItems.filter(ci => bestIds.includes(ci.product_id) && ci.quantity > 0);
  }
}

// CP1 (0.40): User added at least one 48x40 pallet cover pack of 25 or 50 to the cart
checkpoints.push({ passed: anyPalletCartItems.length > 0, weight: 0.40 });

// CP2 (0.60): User added the pack with the lowest price per cover to the cart (quantity >= 1)
checkpoints.push({ passed: bestValueCartItems.length > 0, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const configs = JSON.parse(localStorage.getItem('custom_tarp_configurations') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');

function matchesSize(cfg) {
  return (cfg.width_ft === 18 && cfg.length_ft === 24) || (cfg.width_ft === 24 && cfg.length_ft === 18);
}

const matchingConfigs = configs.filter(cfg => 
  matchesSize(cfg) &&
  typeof cfg.quantity === 'number' && cfg.quantity === 3 &&
  typeof cfg.grommet_spacing_in === 'number' && cfg.grommet_spacing_in === 18 &&
  (cfg.material || '').toLowerCase().startsWith('vinyl') &&
  (cfg.color || '').toLowerCase() === 'blue' &&
  cfg.edge_finish === 'hemmed_edges_with_grommets' &&
  cfg.corner_reinforcement === 'reinforced_corners'
);

const matchingConfigIds = matchingConfigs.map(c => c.id);

const openCart = carts.find(c => c.status === 'open');
let matchingCartItems = [];

if (openCart && matchingConfigIds.length > 0) {
  matchingCartItems = cartItemsAll.filter(ci => 
    ci.cart_id === openCart.id &&
    ci.item_type === 'custom_tarp' &&
    matchingConfigIds.includes(ci.custom_tarp_config_id) &&
    typeof ci.quantity === 'number' && ci.quantity >= 3
  );
}

// CP1 (0.50): A custom tarp configuration was created that matches 18x24 blue vinyl, grommets ~18 in, reinforced corners, quantity 3
checkpoints.push({ passed: matchingConfigs.length > 0, weight: 0.50 });

// CP2 (0.50): That matching custom tarp configuration was added to the cart with quantity >= 3
checkpoints.push({ passed: matchingCartItems.length > 0, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sessions = JSON.parse(localStorage.getItem('checkout_sessions') || '[]');
const shippingAddresses = JSON.parse(localStorage.getItem('shipping_addresses') || '[]');
const shippingMethods = JSON.parse(localStorage.getItem('shipping_methods') || '[]');

let sessionWithAtlanta = null;
let methodForSession = null;

for (const s of sessions) {
  const addr = shippingAddresses.find(a => a.id === s.shipping_address_id);
  if (!addr) continue;
  const cityOk = (addr.city || '').toLowerCase() === 'atlanta';
  const postalOk = (addr.postal_code || '') === '30301';
  const stateVal = (addr.state || '').toLowerCase();
  const stateOk = stateVal === 'georgia' || stateVal === 'ga';
  if (cityOk && stateOk && postalOk) {
    sessionWithAtlanta = s;
    break;
  }
}

if (sessionWithAtlanta) {
  methodForSession = shippingMethods.find(m => m.id === sessionWithAtlanta.shipping_method_id) || null;
}

// CP1 (0.40): There is a checkout session using a shipping address in Atlanta, GA 30301
checkpoints.push({ passed: !!sessionWithAtlanta, weight: 0.40 });

// CP2 (0.30): That session has selected a shipping method with code 'standard_ground'
const hasStandardGround = !!(methodForSession && methodForSession.code === 'standard_ground');
checkpoints.push({ passed: hasStandardGround, weight: 0.30 });

// CP3 (0.30): That session has progressed to the 'payment' step
const atPaymentStep = !!(sessionWithAtlanta && sessionWithAtlanta.current_step === 'payment');
checkpoints.push({ passed: atPaymentStep, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
